import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../../services/axios';

function AdminDashboard() {
  const [stats, setStats] = useState({ totalEvents: 0, totalBookings: 0, totalRevenue: 0 });
  const [recentBookings, setRecentBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    try {
      const [eventsRes, bookingsRes, paymentsRes] = await Promise.all([
        API.get('/events'),
        API.get('/bookings/all/bookings'),
        API.get('/payments/all/payments'),
      ]);
      setStats({
        totalEvents: eventsRes.data.count || 0,
        totalBookings: bookingsRes.data.count || 0,
        totalRevenue: paymentsRes.data.totalRevenue || 0,
      });
      setRecentBookings(bookingsRes.data.bookings?.slice(0, 5) || []);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh' }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎉</div>
        <p style={{ color: '#6b7280' }}>Loading...</p>
      </div>
    </div>
  );

  return (
    <div style={{ padding: '2rem', background: '#f8f7ff', minHeight: '100vh' }}>
      <div style={{ marginBottom: '1.5rem' }}>
        <h1 style={{ fontSize: '1.5rem', fontWeight: '800', color: '#1e1b4b' }}>Dashboard Overview</h1>
        <p style={{ color: '#6b7280', fontSize: '0.85rem', marginTop: '4px' }}>Welcome back, Admin!</p>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1rem', marginBottom: '2rem' }}>
        {[
          { label: 'Total Events', value: stats.totalEvents, icon: '🎭', color: '#7c3aed', bg: '#f5f3ff' },
          { label: 'Total Bookings', value: stats.totalBookings, icon: '🎫', color: '#059669', bg: '#ecfdf5' },
          { label: 'Total Revenue', value: `₹${stats.totalRevenue.toLocaleString()}`, icon: '💰', color: '#d97706', bg: '#fffbeb' },
        ].map(card => (
          <div key={card.label} style={{
            background: 'white', borderRadius: '16px', padding: '1.5rem',
            boxShadow: '0 2px 10px rgba(0,0,0,0.06)', display: 'flex',
            justifyContent: 'space-between', alignItems: 'center',
            border: `1px solid ${card.bg}`
          }}>
            <div>
              <p style={{ color: '#6b7280', fontSize: '0.8rem', marginBottom: '6px' }}>{card.label}</p>
              <p style={{ color: card.color, fontSize: '1.8rem', fontWeight: '800' }}>{card.value}</p>
            </div>
            <div style={{ background: card.bg, width: '50px', height: '50px', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.5rem' }}>{card.icon}</div>
          </div>
        ))}
      </div>

      {/* Quick Actions */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '1rem', marginBottom: '2rem' }}>
        {[
          { to: '/admin/create-event', icon: '➕', label: 'Create Event', color: '#7c3aed' },
          { to: '/admin/manage-events', icon: '📝', label: 'Manage Events', color: '#2563eb' },
          { to: '/admin/bookings', icon: '📊', label: 'All Bookings', color: '#059669' },
        ].map(action => (
          <Link key={action.to} to={action.to} style={{
            background: 'white', borderRadius: '14px', padding: '1.2rem',
            textDecoration: 'none', boxShadow: '0 2px 10px rgba(0,0,0,0.06)',
            textAlign: 'center', transition: 'all 0.2s', border: '2px solid transparent',
            display: 'block'
          }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = action.color; e.currentTarget.style.transform = 'translateY(-2px)'; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = 'transparent'; e.currentTarget.style.transform = 'translateY(0)'; }}
          >
            <div style={{ fontSize: '2rem', marginBottom: '8px' }}>{action.icon}</div>
            <p style={{ color: action.color, fontWeight: '600', fontSize: '0.85rem' }}>{action.label}</p>
          </Link>
        ))}
      </div>

      {/* Recent Bookings */}
      <div style={{ background: 'white', borderRadius: '16px', padding: '1.5rem', boxShadow: '0 2px 10px rgba(0,0,0,0.06)' }}>
        <h2 style={{ fontWeight: '700', color: '#1e1b4b', marginBottom: '1.2rem' }}>Recent Bookings</h2>
        {recentBookings.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '2rem', color: '#9ca3af' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>📦</div>
            <p>No bookings yet</p>
          </div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.85rem' }}>
            <thead>
              <tr style={{ background: '#f8f7ff' }}>
                {['ID', 'User', 'Event', 'Tickets', 'Amount', 'Status'].map(h => (
                  <th key={h} style={{ padding: '10px 14px', textAlign: 'left', color: '#6b7280', fontWeight: '600', fontSize: '0.75rem' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {recentBookings.map(b => (
                <tr key={b._id} style={{ borderBottom: '1px solid #f3f4f6' }}>
                  <td style={{ padding: '12px 14px', color: '#9ca3af', fontFamily: 'monospace', fontSize: '0.75rem' }}>#{b._id.slice(-6).toUpperCase()}</td>
                  <td style={{ padding: '12px 14px', fontWeight: '600', color: '#1f2937' }}>{b.user?.name}</td>
                  <td style={{ padding: '12px 14px', color: '#4b5563' }}>{b.event?.name}</td>
                  <td style={{ padding: '12px 14px', color: '#4b5563' }}>{b.numberOfTickets}</td>
                  <td style={{ padding: '12px 14px', fontWeight: '700', color: '#7c3aed' }}>₹{b.totalAmount}</td>
                  <td style={{ padding: '12px 14px' }}>
                    <span style={{
                      padding: '4px 10px', borderRadius: '20px', fontSize: '0.75rem', fontWeight: '600',
                      background: b.status === 'confirmed' ? '#d1fae5' : b.status === 'pending' ? '#fef3c7' : '#fee2e2',
                      color: b.status === 'confirmed' ? '#065f46' : b.status === 'pending' ? '#92400e' : '#991b1b'
                    }}>{b.status}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
export default AdminDashboard;
